/**
 * SpringApproach.stories.js
 *
 * Concept: Spring-based animation has no native CSS type. Teams have three positions:
 * avoid springs on web, hardcode linear() by hand, or run a resolver in the build pipeline.
 * Each position has different token architecture implications.
 */

import { SPRING_CONFIGS, cubicBezierCSS } from './tokens.js';
import { springToLinear, fromDampingRatio } from './spring-resolver.js';
import { BASE_STYLES } from './shared-styles.js';

export default {
  title: 'Concepts/Spring Approach',
  parameters: { layout: 'fullscreen' },
};

// Pre-resolve spring configs for use across stories
const CRISP_RESOLVED  = springToLinear(SPRING_CONFIGS.crisp.stiffness,  SPRING_CONFIGS.crisp.damping,  SPRING_CONFIGS.crisp.mass);
const GENTLE_RESOLVED = springToLinear(SPRING_CONFIGS.gentle.stiffness, SPRING_CONFIGS.gentle.damping, SPRING_CONFIGS.gentle.mass);
const BOUNCY_RESOLVED = springToLinear(SPRING_CONFIGS.bouncy.stiffness, SPRING_CONFIGS.bouncy.damping, SPRING_CONFIGS.bouncy.mass);

// Standard tween easing for comparison
const TWEEN_ENTER_CSS = cubicBezierCSS([0, 0, 0.2, 1]);

// ---------------------------------------------------------------------------
// Story 1 — ThreePositions
// ---------------------------------------------------------------------------
export const ThreePositions = {
  name: 'Three positions on spring on the web',
  render: () => {
    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${BASE_STYLES}
        .cols { display: grid; grid-template-columns: repeat(3, 1fr); gap: 24px; margin-top: 8px; }
        .col { background: #fff; border: 1px solid #e0e0e0; border-radius: 8px; padding: 20px; }
        .col-name { font-size: 14px; font-weight: 700; color: #1a1a1a; margin-bottom: 2px; }
        .col-sub  { font-size: 11px; color: #888; text-transform: uppercase; letter-spacing: 0.07em; margin-bottom: 14px; }
        .col-tokens { font-size: 11px; font-family: monospace; line-height: 1.8; color: #444; background: #f8f8f8; border-radius: 4px; padding: 10px 12px; margin-bottom: 14px; }
        .col-callout { font-size: 11px; color: #555; line-height: 1.5; font-style: italic; border-top: 1px solid #f0f0f0; padding-top: 10px; margin-top: 10px; }
        .stage { width:100%; height:65px; background:#ececec; border-radius:5px; overflow:hidden; position:relative; margin-bottom:8px; }
        .pipeline { background: #f4f4f4; border: 1px solid #e0e0e0; border-radius: 5px; padding: 10px 12px; margin-bottom: 12px; font-size: 11px; color: #333; line-height: 1.8; }
        .pipe-arrow { color: #aaa; margin: 0 4px; }
        .platform-blocks { display: flex; flex-direction: column; gap: 6px; margin-bottom: 12px; }
        .platform-block { background: #f8f8f8; border: 1px solid #e8e8e8; border-radius: 4px; padding: 8px 10px; }
        .platform-name { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.07em; color: #888; margin-bottom: 4px; }
        .platform-code { font-family: monospace; font-size: 11px; color: #333; }
        .comparison { display: flex; gap: 10px; margin-bottom: 12px; }
        .comp-box { flex: 1; }
        .comp-label { font-size: 10px; text-transform: uppercase; letter-spacing: 0.06em; color: #888; margin-bottom: 4px; }
      </style>
      <div class="page">
        <div class="concept-header">
          <div class="concept-header-title">Spring on the web — three positions</div>
          <div class="concept-header-body">
            CSS has no native spring type. Duration + cubic-bezier is the native model. Teams working with spring-based motion on the web must choose one of three positions: avoid springs entirely and use cubic-bezier curves, hardcode the CSS linear() approximation by hand, or run a resolver in the build pipeline that converts spring configs to linear() at build time. Each position has different implications for the token architecture.
          </div>
        </div>

        <div class="cols">
          <!-- Column A: Avoid -->
          <div class="col">
            <div class="col-name">Column A — Avoid</div>
            <div class="col-sub">Most web-only systems</div>
            <div class="col-tokens">
duration.300 = 300ms<br>
easing.enter = cubic-bezier(0,0,0.2,1)<br>
<span style="color:#aaa;">// no spring tokens</span>
            </div>

            <div style="font-size:11px; color:#555; margin-bottom:6px;">Spring (spring.config.gentle):</div>
            <div class="stage">
              <div id="springViz" style="width:50px;height:50px;background:#5566ee;border-radius:4px;position:absolute;top:7px;left:-55px;"></div>
            </div>

            <div style="font-size:11px; color:#555; margin-bottom:6px;">Cubic-bezier (same duration):</div>
            <div class="stage">
              <div id="tweenViz" style="width:50px;height:50px;background:#ee6655;border-radius:4px;position:absolute;top:7px;left:-55px;"></div>
            </div>

            <button class="play-btn" id="playAvoid">Compare both</button>

            <div class="col-callout">Most web systems are here by default, not by choice. The spring settles organically and can overshoot; the cubic-bezier follows a fixed mathematical curve throughout.</div>
          </div>

          <!-- Column B: Resolve at build time -->
          <div class="col">
            <div class="col-name">Column B — Resolve at build</div>
            <div class="col-sub">This token set's approach</div>
            <div class="pipeline">
              <div><strong>spring.config.crisp</strong></div>
              <div>{ stiffness: ${SPRING_CONFIGS.crisp.stiffness}, damping: ${SPRING_CONFIGS.crisp.damping}, mass: ${SPRING_CONFIGS.crisp.mass} }</div>
              <div><span class="pipe-arrow">↓</span> springToLinear()</div>
              <div><span class="pipe-arrow">↓</span> CSS linear()</div>
              <div style="font-size:10px; color:#888; word-break:break-all;">${CRISP_RESOLVED.css.slice(0, 60)}...</div>
            </div>
            <div class="stage">
              <div id="resolvedBox" style="width:50px;height:50px;background:#007755;border-radius:4px;position:absolute;top:7px;left:-55px;"></div>
            </div>
            <button class="play-btn" id="playResolved" style="margin-bottom:12px;">Animate resolved spring</button>
            <div style="font-size:11px; color:#555; margin-bottom:4px;">Computed duration: <strong>${CRISP_RESOLVED.duration}ms</strong> | Damping ratio: <strong>${CRISP_RESOLVED.dampingRatio}</strong></div>
            <div class="col-callout">The resolver bridges the gap. The token stores intent (spring config); the build pipeline outputs platform-native code (linear()). The author never writes the linear() string by hand.</div>
          </div>

          <!-- Column C: Platform-native -->
          <div class="col">
            <div class="col-name">Column C — Platform-native</div>
            <div class="col-sub">Apple + Android (conceptual)</div>
            <div class="platform-blocks">
              <div class="platform-block">
                <div class="platform-name">Spring config (token)</div>
                <div class="platform-code">{ stiffness: 200, damping: 20, mass: 1 }</div>
              </div>
              <div class="platform-block">
                <div class="platform-name">CSS linear() (web resolver)</div>
                <div class="platform-code" style="font-size:9px; word-break:break-all;">${GENTLE_RESOLVED.css.slice(0, 55)}...</div>
              </div>
              <div class="platform-block">
                <div class="platform-name">Apple SwiftUI</div>
                <div class="platform-code">.spring(response: 0.45, dampingFraction: 0.8)</div>
              </div>
              <div class="platform-block">
                <div class="platform-name">Android Compose</div>
                <div class="platform-code">spring(stiffness=200f, dampingRatio=0.8f)</div>
              </div>
            </div>
            <div class="col-callout">Native platforms have first-class spring types. The same spring config resolves to different syntax per platform. The token holds the intent once; each resolver produces the appropriate output.</div>
          </div>
        </div>
      </div>
    `;

    // Compare: spring vs tween
    el.querySelector('#playAvoid').addEventListener('click', function() {
      if (this._animating) return;
      this._animating = true;
      this.disabled = true;
      const springBox = el.querySelector('#springViz');
      const tweenBox  = el.querySelector('#tweenViz');
      let done = 0;
      const onDone = () => { done++; if (done === 2) { this._animating = false; this.disabled = false; } };
      springBox.animate(
        [{ left: '-55px', opacity: 0 }, { left: '5px', opacity: 1 }],
        { duration: GENTLE_RESOLVED.duration, easing: GENTLE_RESOLVED.css, fill: 'forwards' }
      ).onfinish = onDone;
      tweenBox.animate(
        [{ left: '-55px', opacity: 0 }, { left: '5px', opacity: 1 }],
        { duration: GENTLE_RESOLVED.duration, easing: TWEEN_ENTER_CSS, fill: 'forwards' }
      ).onfinish = onDone;
    });

    // Resolved spring
    el.querySelector('#playResolved').addEventListener('click', function() {
      const box = el.querySelector('#resolvedBox');
      if (box._animating) return;
      box._animating = true;
      this.disabled = true;
      box.animate(
        [{ left: '-55px', opacity: 0 }, { left: '5px', opacity: 1 }],
        { duration: CRISP_RESOLVED.duration, easing: CRISP_RESOLVED.css, fill: 'forwards' }
      ).onfinish = () => { box._animating = false; this.disabled = false; };
    });

    return el;
  },
};

// ---------------------------------------------------------------------------
// Story 2 — SpatialVsEffects
// ---------------------------------------------------------------------------
export const SpatialVsEffects = {
  name: 'Spatial vs. effects springs (MD3)',
  render: () => {
    // MD3 default spatial: damping=0.9, stiffness=700
    const md3SpatialParams = fromDampingRatio(700, 0.9, 1);
    const md3SpatialResolved = springToLinear(md3SpatialParams.stiffness, md3SpatialParams.damping, md3SpatialParams.mass);

    // MD3 default effects: damping=1.0, stiffness=1600 (critically damped)
    const md3EffectsParams = fromDampingRatio(1600, 1.0, 1);
    const md3EffectsResolved = springToLinear(md3EffectsParams.stiffness, md3EffectsParams.damping, md3EffectsParams.mass);

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${BASE_STYLES}
        .panels { display: grid; grid-template-columns: 1fr 1fr; gap: 32px; margin-top: 8px; }
        .panel { background: #fff; border: 1px solid #e0e0e0; border-radius: 8px; padding: 24px; }
        .panel-title { font-size: 15px; font-weight: 700; color: #1a1a1a; margin-bottom: 2px; }
        .panel-token { font-family: monospace; font-size: 12px; color: #555; margin-bottom: 4px; }
        .panel-params { font-size: 11px; color: #888; margin-bottom: 16px; }
        .stage { width:100%; height:80px; background:#ececec; border-radius:6px; overflow:hidden; position:relative; margin-bottom:8px; }
        .panel-note { font-size: 12px; color: #555; line-height: 1.5; margin-top: 8px; }
        .overshoot-label { font-size: 10px; text-transform: uppercase; letter-spacing: 0.06em; color: #888; position: absolute; right: 6px; top: 6px; }
      </style>
      <div class="page">
        <div class="concept-header">
          <div class="concept-header-title">Spatial vs. effects springs (MD3)</div>
          <div class="concept-header-body">
            Not all animated properties can safely overshoot. Position and size can slightly exceed their target and snap back — this produces a natural, physical feel. Opacity and color cannot: an element at 105% opacity is clamped or produces an artifact. Material Design 3 encodes this constraint directly in the token architecture by publishing separate spring tokens for spatial and effects properties.
          </div>
        </div>

        <div class="panels">
          <!-- Spatial spring -->
          <div class="panel">
            <div class="panel-title">motionSpringDefaultSpatial</div>
            <div class="panel-token">dampingRatio = 0.9 (slight overshoot)</div>
            <div class="panel-params">Stiffness: 700 | Settlement: ~${md3SpatialResolved.duration}ms</div>
            <div style="font-size:12px; color:#555; margin-bottom:10px;">Animating position (translateX). The slight overshoot is visible and correct — like a physical object settling.</div>
            <div class="stage">
              <div id="spatialBox" style="width:60px;height:60px;background:#6750a4;border-radius:6px;position:absolute;top:10px;left:10px;display:flex;align-items:center;justify-content:center;color:#fff;font-size:10px;font-weight:700;"></div>
              <div class="overshoot-label">overshoot OK</div>
            </div>
            <button class="play-btn" id="playSpatial">Animate position</button>
            <div class="panel-note">Used for: position changes, size changes, layout transitions. Slight overshoot produces a physical, grounded feel.</div>
          </div>

          <!-- Effects spring -->
          <div class="panel">
            <div class="panel-title">motionSpringDefaultEffects</div>
            <div class="panel-token">dampingRatio = 1.0 (critically damped — no overshoot)</div>
            <div class="panel-params">Stiffness: 1600 | Settlement: ~${md3EffectsResolved.duration}ms</div>
            <div style="font-size:12px; color:#555; margin-bottom:10px;">Animating opacity. No overshoot — opacity exceeding 100% would break the interface.</div>
            <div class="stage" style="background:#e8e8e8;">
              <div id="effectsBox" style="width:100%;height:100%;background:#6750a4;border-radius:5px;position:absolute;top:0;left:0;opacity:0;display:flex;align-items:center;justify-content:center;color:#fff;font-size:11px;font-weight:700;">Surface</div>
              <div class="overshoot-label" style="color:#cc3300;">no overshoot</div>
            </div>
            <button class="play-btn" id="playEffects">Animate opacity</button>
            <div class="panel-note">Used for: opacity, color, blur. Critical damping ensures the value never exceeds its target — required for properties with hard bounds.</div>
          </div>
        </div>

        <div class="note" style="margin-top:24px;">
          MD3 encodes the constraint in the token. A component author selecting <span style="font-family:monospace;">motionSpringDefaultSpatial</span> for a position change, and <span style="font-family:monospace;">motionSpringDefaultEffects</span> for an opacity change, cannot accidentally apply the overshooting spring to opacity — because those are different tokens. The architecture makes the wrong choice structurally harder to make.
        </div>
      </div>
    `;

    el.querySelector('#playSpatial').addEventListener('click', function() {
      const box = el.querySelector('#spatialBox');
      if (box._animating) return;
      box._animating = true;
      this.disabled = true;
      const stage = box.parentElement;
      const travel = stage.offsetWidth - 80;
      box.animate(
        [{ transform: 'translateX(0)' }, { transform: `translateX(${travel}px)` }, { transform: 'translateX(0)' }],
        { duration: md3SpatialResolved.duration * 2, easing: md3SpatialResolved.css, fill: 'forwards' }
      ).onfinish = () => { box._animating = false; this.disabled = false; };
    });

    el.querySelector('#playEffects').addEventListener('click', function() {
      const box = el.querySelector('#effectsBox');
      if (box._animating) return;
      box._animating = true;
      this.disabled = true;
      box.animate(
        [{ opacity: 0 }, { opacity: 1 }],
        { duration: md3EffectsResolved.duration, easing: md3EffectsResolved.css, fill: 'forwards' }
      ).onfinish = () => { box._animating = false; this.disabled = false; };
    });

    return el;
  },
};

