// Story 3 — DampingExplorer
// ---------------------------------------------------------------------------
export const DampingExplorer = {
  name: 'Damping ratio explorer',
  render: () => {
    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${BASE_STYLES}
        .explorer { background: #fff; border: 1px solid #e0e0e0; border-radius: 8px; padding: 24px; max-width: 680px; }
        .slider-row { display: flex; align-items: center; gap: 16px; margin-bottom: 20px; }
        .slider { flex: 1; -webkit-appearance: none; height: 4px; background: #e0e0e0; border-radius: 2px; outline: none; }
        .slider::-webkit-slider-thumb { -webkit-appearance: none; width: 20px; height: 20px; border-radius: 50%; background: #1a1a1a; cursor: pointer; }
        .slider-val { font-size: 20px; font-weight: 700; font-family: monospace; color: #1a1a1a; min-width: 48px; }
        .stats-row { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; margin-bottom: 16px; }
        .stat-card { background: #f8f8f8; border-radius: 5px; padding: 10px 12px; }
        .stat-label { font-size: 10px; text-transform: uppercase; letter-spacing: 0.07em; color: #888; margin-bottom: 3px; }
        .stat-val { font-size: 16px; font-weight: 700; color: #1a1a1a; font-family: monospace; }
        .behavior-badge { display: inline-block; padding: 4px 10px; border-radius: 12px; font-size: 12px; font-weight: 700; }
        .stage { width: 100%; height: 80px; background: #ececec; border-radius: 6px; overflow: hidden; position: relative; margin-bottom: 16px; }
        .zones { display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; margin-top: 16px; font-size: 11px; }
        .zone { padding: 8px 10px; border-radius: 4px; }
        .zone-label { font-weight: 700; margin-bottom: 3px; }
        .zone-desc { color: #666; line-height: 1.4; }
      </style>
      <div class="page">
        <div class="concept-header">
          <div class="concept-header-title">Damping ratio explorer</div>
          <div class="concept-header-body">
            The damping ratio is the single most important parameter in a spring config — it determines whether the spring oscillates, settles cleanly, or overshoots. Values below 1.0 produce underdamped (bouncy) behavior. A value of exactly 1.0 is critically damped — fastest non-oscillatory settle. Values above 1.0 are overdamped and settle slowly. This explorer makes the physics intuitive without requiring math knowledge.
          </div>
        </div>

        <div class="explorer">
          <div class="slider-row">
            <span style="font-size:12px; color:#888;">Bouncy</span>
            <input class="slider" id="dampingSlider" type="range" min="20" max="200" value="80" step="1">
            <span style="font-size:12px; color:#888;">Sluggish</span>
            <span class="slider-val" id="dampingVal">0.80</span>
          </div>

          <div class="stats-row">
            <div class="stat-card">
              <div class="stat-label">Damping ratio</div>
              <div class="stat-val" id="statRatio">0.80</div>
            </div>
            <div class="stat-card">
              <div class="stat-label">Settlement time</div>
              <div class="stat-val" id="statDuration">—</div>
            </div>
            <div class="stat-card">
              <div class="stat-label">Behavior</div>
              <div id="statBehavior" class="behavior-badge" style="background:#fff3cd; color:#856404;">Underdamped</div>
            </div>
          </div>

          <div class="stage">
            <div id="explorerBox" style="width:55px;height:55px;background:#5566ee;border-radius:6px;position:absolute;top:12px;left:10px;display:flex;align-items:center;justify-content:center;color:#fff;font-size:9px;font-weight:700;"></div>
          </div>

          <button class="play-btn" id="playExplorer">Animate at this damping ratio</button>

          <div class="zones">
            <div class="zone" style="background:#fff3cd;">
              <div class="zone-label" style="color:#856404;">Underdamped (< 1.0)</div>
              <div class="zone-desc">Oscillates before settling. Visible bounce. Correct for spatial properties, never for opacity.</div>
            </div>
            <div class="zone" style="background:#d4edda;">
              <div class="zone-label" style="color:#155724;">Critically damped (= 1.0)</div>
              <div class="zone-desc">Fastest settle without oscillation. No overshoot. Safe for all property types.</div>
            </div>
            <div class="zone" style="background:#f8d7da;">
              <div class="zone-label" style="color:#721c24;">Overdamped (> 1.0)</div>
              <div class="zone-desc">Slow approach, no oscillation. Can feel sluggish. Used intentionally for deliberate UI patterns.</div>
            </div>
          </div>
        </div>
      </div>
    `;

    const slider = el.querySelector('#dampingSlider');
    const valLabel = el.querySelector('#dampingVal');
    const statRatio = el.querySelector('#statRatio');
    const statDuration = el.querySelector('#statDuration');
    const statBehavior = el.querySelector('#statBehavior');
    const playBtn = el.querySelector('#playExplorer');
    let currentResolved = null;

    function updateStats(sliderVal) {
      const ratio = sliderVal / 100;
      const stiffness = 300;
      const damping = ratio * 2 * Math.sqrt(stiffness * 1);
      currentResolved = springToLinear(stiffness, damping, 1);

      valLabel.textContent = ratio.toFixed(2);
      statRatio.textContent = ratio.toFixed(2);
      statDuration.textContent = currentResolved.duration + 'ms';

      let behavior, bg, color;
      if (ratio < 0.98) {
        behavior = 'Underdamped'; bg = '#fff3cd'; color = '#856404';
      } else if (ratio <= 1.02) {
        behavior = 'Critically damped'; bg = '#d4edda'; color = '#155724';
      } else {
        behavior = 'Overdamped'; bg = '#f8d7da'; color = '#721c24';
      }
      statBehavior.textContent = behavior;
      statBehavior.style.background = bg;
      statBehavior.style.color = color;
    }

    updateStats(parseInt(slider.value, 10));

    slider.addEventListener('input', () => updateStats(parseInt(slider.value, 10)));

    playBtn.addEventListener('click', function() {
      const box = el.querySelector('#explorerBox');
      if (box._animating || !currentResolved) return;
      box._animating = true;
      this.disabled = true;
      const stage = box.parentElement;
      const travel = (stage.offsetWidth || 300) - 75;
      box.animate(
        [{ transform: 'translateX(0)' }, { transform: `translateX(${travel}px)` }],
        { duration: currentResolved.duration, easing: currentResolved.css, fill: 'forwards' }
      ).onfinish = () => {
        box.animate(
          [{ transform: `translateX(${travel}px)` }, { transform: 'translateX(0)' }],
          { duration: 200, easing: 'ease-in', fill: 'forwards' }
        ).onfinish = () => { box._animating = false; this.disabled = false; };
      };
    });

    return el;
  },
};
